from enum import Enum
from plum import dispatch
from typing import TypeVar,Union,Generic,List,Tuple
from spire.pdf.common import *
from spire.pdf import *
from ctypes import *
import abc

class PdfGrayConverter (SpireObject) :
    """
    The gray pdf conveter.
    """
    @dispatch
    def __init__(self, filePath:str):
        GetDllLibPdf().spr_pdf_PdfGrayConverter_CreatePdfGrayConverterF.argtypes=[c_wchar_p]
        GetDllLibPdf().spr_pdf_PdfGrayConverter_CreatePdfGrayConverterF.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfGrayConverter_CreatePdfGrayConverterF,filePath)
        super(PdfGrayConverter, self).__init__(intPtr)

    @dispatch
    def __init__(self, stream:Stream):
        ptrStream:c_void_p = stream.Ptr
        GetDllLibPdf().spr_pdf_PdfGrayConverter_CreatePdfGrayConverterS.argtypes=[c_void_p]
        GetDllLibPdf().spr_pdf_PdfGrayConverter_CreatePdfGrayConverterS.restype = c_void_p
        intPtr = CallCFunction(GetDllLibPdf().spr_pdf_PdfGrayConverter_CreatePdfGrayConverterS,ptrStream)
        super(PdfGrayConverter, self).__init__(intPtr)

    @dispatch

    def ToGrayPdf(self ,filePath:str):
        """
        Convert to gray pdf document.

        Args:
            filePath: The out file path.
        """
        GetDllLibPdf().spr_pdf_PdfGrayConverter_ToGrayPdf.argtypes=[c_void_p ,c_wchar_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfGrayConverter_ToGrayPdf,self.Ptr, filePath)

    @dispatch

    def ToGrayPdf(self ,stream:Stream):
        """
        Convert to gray pdf document.

        Args:
            stream: The out stream.
        """
        intPtrstream:c_void_p = stream.Ptr

        GetDllLibPdf().spr_pdf_PdfGrayConverter_ToGrayPdfS.argtypes=[c_void_p ,c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfGrayConverter_ToGrayPdfS,self.Ptr, intPtrstream)

    def Dispose(self):
        """

        """
        GetDllLibPdf().spr_pdf_PdfGrayConverter_Dispose.argtypes=[c_void_p]
        CallCFunction(GetDllLibPdf().spr_pdf_PdfGrayConverter_Dispose,self.Ptr)

